public static readonly LlamaLibrary.Logging.LLogger Log = new("ARR", Colors.DeepPink);

private static readonly string[] TutorialWindows =
{
    "HowToNotice",
    "HowTo",
    "PlayGuide",
    "JobHudNotice",
    "ContentsTutorial",
    "RecommendList",
    "AchievementInfo",
    "CreditScroll",
};



        bool hasTutorialWindow = TutorialWindows
            .Any(window => RaptureAtkUnitManager.GetWindowByName(window) != null);

        if (RaptureAtkUnitManager.GetWindowByName("CreditScroll") != null)
        {
            RaptureAtkUnitManager.GetWindowByName("CreditScroll").SendAction(1, 3uL, 0xFFFFFFFFuL);
        }

        if (RaptureAtkUnitManager.GetWindowByName("CreditPlayer") != null)
        {
            RaptureAtkUnitManager.GetWindowByName("CreditPlayer").SendAction(1, 3uL, 0xFFFFFFFFuL);
        }

        if (hasTutorialWindow)
        {
            await LlamaLibrary.Helpers.GeneralFunctions.CloseHowTos();
        }

			  return false;
